```gdscript
class_name SpatialGrid extends RefCounted

var cell_size: float = 64.0
var cells: Dictionary = {}  # Vector2i -> PackedInt32Array

func clear():
    cells.clear()

func get_cell_key(world_pos: Vector2) -> Vector2i:
    return Vector2i(int(world_pos.x / cell_size), int(world_pos.y / cell_size))
```

**res://logic/spatial_index.gd:**
```gdscript
class_name SpatialIndex extends RefCounted

static func rebuild(grid: SpatialGrid, enemies: EnemyPool) -> void:
    grid.clear()
    for i in range(enemies.CAPACITY):
        if not enemies.alive[i]: continue
        var key = grid.get_cell_key(enemies.pos[i])
        if not grid.cells.has(key):
            grid.cells[key] = PackedInt32Array()
        grid.cells[key].push_back(i)

static func query_circle(grid: SpatialGrid, enemies: EnemyPool, center: Vector2, radius: float) -> PackedInt32Array:
    var result := PackedInt32Array()
    var radius_sq := radius * radius
    var min_cell := grid.get_cell_key(center - Vector2(radius, radius))
    var max_cell := grid.get_cell_key(center + Vector2(radius, radius))

    for cx in range(min_cell.x, max_cell.x + 1):
        for cy in range(min_cell.y, max_cell.y + 1):
            var key := Vector2i(cx, cy)
            if not grid.cells.has(key): continue
            for idx in grid.cells[key]:
                if not enemies.alive[idx]: continue
                if center.distance_squared_to(enemies.pos[idx]) <= radius_sq:
                    result.push_back(idx)
    return result
```

This avoids running Area2D monitors for 500+ enemies by using pure data lookup with O(1) cell access.

**res://nodes/player_shell.gd:**
```gdscript
extends Node2D

var player_state: PlayerState

@onready var sprite: AnimatedSprite2D = $AnimatedSprite2D
@onready var health_bar: ProgressBar = $HealthBar  # Or custom Sprite2D-based
@onready var camera: Camera2D = $Camera2D

const CAMERA_ZOOM := 2  # Integer zoom for pixel-perfect rendering

func _ready() -> void:
    camera.zoom = Vector2(CAMERA_ZOOM, CAMERA_ZOOM)

func init(state: PlayerState) -> void:
    player_state = state
    position = state.pos

func _gather_input() -> Vector2:
    var input := Input.get_vector("move_left", "move_right", "move_up", "move_down")

    # Normalize to 8-directional
    if input.length() > 0.1:
        # Round to 8 directions
        var angle := input.angle()
        var snapped := snappedf(angle, PI / 4)
        input = Vector2.from_angle(snapped)

    return input

func get_camera_rect() -> Rect2:
    var viewport_size := get_viewport_rect().size
    var world_size := viewport_size / camera.zoom
    var center := position
    return Rect2(center - world_size / 2, world_size)

func render(state: PlayerState) -> void:
    position = state.pos

    # Flip sprite based on facing
    if state.facing.x < 0:
        sprite.flip_h = true
    elif state.facing.x > 0:
        sprite.flip_h = false

    # Animation state
    if state.vel.length() > 0.1:
        sprite.play("walk")
    else:
        sprite.play("idle")

    # I-frame flash
    if state.iframe_timer > 0:
        sprite.modulate.a = 0.5 + 0.5 * sin(state.iframe_timer * 30)
    else:
        sprite.modulate.a = 1.0

    # Health bar
    health_bar.value = state.hp / state.max_hp * 100
    health_bar.visible = state.hp < state.max_hp
```

