**res://nodes/view_sync.gd:**
```gdscript
extends Node

var run_state: RunState
var game_db: Node

# Pre-instanced node pools
var enemy_sprites: Array[AnimatedSprite2D] = []
var projectile_sprites: Array[Sprite2D] = []
var pickup_sprites: Array[Sprite2D] = []
var floater_labels: Array[Label] = []

@onready var enemy_layer: Node2D = get_parent().get_node("World/EnemyLayer")
@onready var projectile_layer: Node2D = get_parent().get_node("World/ProjectileLayer")
@onready var pickup_layer: Node2D = get_parent().get_node("World/PickupLayer")
@onready var floater_layer: Node2D = get_parent().get_node("World/FloatingTextLayer")

func init(state: RunState, db: Node) -> void:
    run_state = state
    game_db = db
    _create_enemy_pool(512)
    _create_projectile_pool(256)
    _create_pickup_pool(512)
    _create_floater_pool(64)

func _create_enemy_pool(count: int) -> void:
    for i in range(count):
        var sprite := AnimatedSprite2D.new()
        sprite.visible = false
        enemy_layer.add_child(sprite)
        enemy_sprites.append(sprite)

func _create_projectile_pool(count: int) -> void:
    for i in range(count):
        var sprite := Sprite2D.new()
        sprite.visible = false
        projectile_layer.add_child(sprite)
        projectile_sprites.append(sprite)

func _create_pickup_pool(count: int) -> void:
    for i in range(count):
        var sprite := Sprite2D.new()
        sprite.visible = false
        pickup_layer.add_child(sprite)
        pickup_sprites.append(sprite)

func _create_floater_pool(count: int) -> void:
    for i in range(count):
        var label := Label.new()
        label.visible = false
        floater_layer.add_child(label)
        floater_labels.append(label)

func sync_enemies(enemies: EnemyPool) -> void:
    for i in range(mini(enemy_sprites.size(), enemies.CAPACITY)):
        var sprite := enemy_sprites[i]
        if enemies.alive[i]:
            sprite.visible = true
            sprite.position = enemies.pos[i]

            # Hit flash
            if enemies.hit_flash[i] > 0:
                sprite.modulate = Color.WHITE
            else:
                sprite.modulate = Color(1, 1, 1, 1)

            # Animation from type_id -> SpriteFrames lookup
            # var def := game_db.enemy(enemies.type_id[i])
            # sprite.sprite_frames = def.sprite_frames
        else:
            sprite.visible = false

func sync_projectiles(projectiles: ProjectilePool) -> void:
    for i in range(mini(projectile_sprites.size(), projectiles.CAPACITY)):
        var sprite := projectile_sprites[i]
        if projectiles.alive[i]:
            sprite.visible = true
            sprite.position = projectiles.pos[i]
            sprite.scale = Vector2.ONE * projectiles.area_scale[i]
            # Rotation from velocity
            if projectiles.vel[i].length_squared() > 0:
                sprite.rotation = projectiles.vel[i].angle()
        else:
            sprite.visible = false

func sync_pickups(pickups: PickupPool) -> void:
    for i in range(mini(pickup_sprites.size(), pickups.CAPACITY)):
        var sprite := pickup_sprites[i]
        if pickups.alive[i]:
            sprite.visible = true
            sprite.position = pickups.pos[i]
            # Visual from kind + gem_tier
        else:
            sprite.visible = false

func sync_floaters(floaters: FloatingTextPool) -> void:
    for i in range(mini(floater_labels.size(), floaters.CAPACITY)):
        var label := floater_labels[i]
        if floaters.alive[i]:
            label.visible = true
            label.position = floaters.pos[i]
            label.text = floaters.text[i]
        else:
            label.visible = false
```

**res://nodes/hud.gd:**
```gdscript
extends Control

@onready var xp_bar: ProgressBar = $XPBar
@onready var timer_label: Label = $TimerLabel
@onready var gold_label: Label = $GoldLabel
@onready var kills_label: Label = $KillsLabel
@onready var level_label: Label = $LevelLabel
@onready var weapon_container: HBoxContainer = $WeaponContainer
@onready var passive_container: HBoxContainer = $PassiveContainer

@onready var game_manager := get_node("/root/GameManager")

func _process(_delta: float) -> void:
    if game_manager.run_state == null: return
    var player := game_manager.run_state.player
    var elapsed := game_manager.run_state.elapsed

    # XP bar
    xp_bar.value = player.xp / player.xp_to_next * 100

    # Timer (MM:SS format)
    var minutes := int(elapsed) / 60
    var seconds := int(elapsed) % 60
    timer_label.text = "%02d:%02d" % [minutes, seconds]

    # Stats
    gold_label.text = str(player.gold)
    kills_label.text = str(player.kills)
    level_label.text = "LV %d" % player.level

    # Update inventory icons (only when changed)
    _update_inventory(player)

func _update_inventory(player: PlayerState) -> void:
    # Clear and rebuild weapon icons
    for child in weapon_container.get_children():
        child.queue_free()

    for weapon in player.weapons:
        var icon := TextureRect.new()
        icon.custom_minimum_size = Vector2(32, 32)
        # icon.texture = preload weapon icon by ID
        weapon_container.add_child(icon)

    # Same for passives
    for child in passive_container.get_children():
        child.queue_free()

    for passive in player.passives:
        var icon := TextureRect.new()
        icon.custom_minimum_size = Vector2(32, 32)
        passive_container.add_child(icon)
```

**Layout anchors:**
- XPBar: top stretch (full width, anchored top)
- TimerLabel: top-center
- GoldLabel, KillsLabel, LevelLabel: top-right
- WeaponContainer, PassiveContainer: top-left below XP bar

**res://nodes/pause_screen.gd:**
```gdscript
extends Control

@onready var build_container: VBoxContainer = $Panel/BuildContainer
@onready var resume_button: Button = $Panel/ResumeButton
@onready var quit_button: Button = $Panel/QuitButton

@onready var game_manager := get_node("/root/GameManager")

func _ready() -> void:
    process_mode = Node.PROCESS_MODE_ALWAYS
    visible = false
    game_manager.state_changed.connect(_on_state_changed)
    resume_button.pressed.connect(_on_resume)
    quit_button.pressed.connect(_on_quit)

func _on_state_changed(new_state: int) -> void:
    visible = (new_state == game_manager.State.PAUSED)
    if visible:
        _update_build_display()

func _update_build_display() -> void:
    var player := game_manager.run_state.player
    # Show weapons and passives with levels
    for child in build_container.get_children():
        child.queue_free()

    for weapon in player.weapons:
        var label := Label.new()
        label.text = "%s LV%d" % [weapon.id, weapon.level]
        build_container.add_child(label)

    for passive in player.passives:
        var label := Label.new()
        label.text = "%s LV%d" % [passive.id, passive.level]
        build_container.add_child(label)

func _on_resume() -> void:
    game_manager.resume()

func _on_quit() -> void:
    game_manager.to_menu()
```

**res://nodes/result_screen.gd:**
```gdscript
extends Control

@onready var time_label: Label = $Panel/TimeLabel
@onready var level_label: Label = $Panel/LevelLabel
@onready var kills_label: Label = $Panel/KillsLabel
@onready var gold_label: Label = $Panel/GoldLabel
@onready var restart_button: Button = $Panel/RestartButton
@onready var menu_button: Button = $Panel/MenuButton

@onready var game_manager := get_node("/root/GameManager")

func _ready() -> void:
    process_mode = Node.PROCESS_MODE_ALWAYS
    visible = false
    game_manager.game_over_triggered.connect(_on_game_over)
    restart_button.pressed.connect(_on_restart)
    menu_button.pressed.connect(_on_menu)

func _on_game_over(result: RunResult) -> void:
    visible = true

    var minutes := int(result.survival_time) / 60
    var seconds := int(result.survival_time) % 60
    time_label.text = "Time: %02d:%02d" % [minutes, seconds]
    level_label.text = "Level: %d" % result.final_level
    kills_label.text = "Kills: %d" % result.total_kills
    gold_label.text = "Gold: %d" % result.total_gold

func _on_restart() -> void:
    visible = false
    game_manager.restart()

func _on_menu() -> void:
    visible = false
    game_manager.to_menu()
```
